def validate_redirect_uri_secure(redirect_uri, tenant_config):
    """
    SECURE redirect URI validation using exact match against an allowlist.
    This is the ONLY safe way to validate redirect URIs in OAuth 2.0.

    Per RFC 6749 Section 3.1.2.2: The authorization server MUST require
    the client to pre-register their redirect URIs and MUST compare
    using exact string matching.
    """
    if not redirect_uri:
        return False

    # Parse the URI to ensure it's well-formed
    try:
        parsed = urlparse(redirect_uri)
    except Exception:
        logger.warning(f"Malformed redirect_uri rejected: {redirect_uri}")
        return False

    # Reject non-HTTPS in production
    if parsed.scheme != "https":
        logger.warning(f"Non-HTTPS redirect_uri rejected: {redirect_uri}")
        return False

    # Reject URIs with fragments (per RFC 6749 Section 3.1.2)
    if parsed.fragment:
        logger.warning(f"Redirect URI with fragment rejected: {redirect_uri}")
        return False

    # Reject URIs with userinfo component (potential confusion attacks)
    if parsed.username or parsed.password or "@" in (parsed.netloc or ""):
        logger.warning(f"Redirect URI with userinfo rejected: {redirect_uri}")
        return False

    # EXACT MATCH against pre-registered allowlist
    allowed_uris = tenant_config.get("allowed_redirect_uris", [])
    if redirect_uri in allowed_uris:
        return True

    logger.warning(
        f"Redirect URI not in allowlist: {redirect_uri}. "
        f"Allowed: {allowed_uris}"
    )
    return False


def get_tenant_config(tenant_id):
    """Retrieve and validate tenant configuration."""
    if not tenant_id or not isinstance(tenant_id, str):
        return None

    # Sanitize tenant_id to prevent injection
    tenant_id = tenant_id.strip().lower()
    if not tenant_id.replace("-", "").replace("_", "").isalnum():
        logger.warning(f"Invalid tenant_id format: {tenant_id}")
        return None

    config = TENANT_CONFIGS.get(tenant_id)
    if not config:
        logger.warning(f"Unknown tenant_id: {tenant_id}")
    return config


def generate_state_token():
    """Generate a cryptographically secure state parameter for CSRF protection."""
    return secrets.token_urlsafe(32)


