@app.route("/oauth/authorize")
def oauth_authorize():
    """
    Initiate the OAuth 2.0 Authorization Code flow for a tenant.

    Query Parameters:
        tenant_id: The tenant identifier
        redirect_uri: (Optional) The redirect URI to use. Must be in the
                      tenant's allowlist. Defaults to the tenant's default URI.
    """
    tenant_id = request.args.get("tenant_id")
    redirect_uri = request.args.get("redirect_uri")

    # Validate tenant
    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        logger.warning(f"Authorization request for invalid tenant: {tenant_id}")
        abort(400, description="Invalid or unknown tenant_id")

    # Use default redirect_uri if none specified
    if not redirect_uri:
        redirect_uri = tenant_config["default_redirect_uri"]

    # SECURE validation: exact match against allowlist
    if not validate_redirect_uri_secure(redirect_uri, tenant_config):
        logger.error(
            f"SECURITY: Redirect URI validation failed for tenant '{tenant_id}'. "
            f"Requested URI: '{redirect_uri}'"
        )
        abort(400, description="Invalid redirect_uri. URI must exactly match a pre-registered URI.")

    # Generate CSRF state token
    state = generate_state_token()

    # Store state and context in session for validation on callback
    session["oauth_state"] = state
    session["oauth_tenant_id"] = tenant_id
    session["oauth_redirect_uri"] = redirect_uri

    # Build authorization URL
    auth_params = {
        "response_type": "code",
        "client_id": tenant_config["client_id"],
        "redirect_uri": redirect_uri,
        "scope": tenant_config["scopes"],
        "state": state,
    }

    authorization_url = (
        f"{tenant_config['authorization_endpoint']}?{urlencode(auth_params)}"
    )

    logger.info(
        f"Initiating OAuth flow for tenant '{tenant_id}' "
        f"with redirect_uri '{redirect_uri}'"
    )

    return redirect(authorization_url)


@app.route("/callback")
def oauth_callback():
    """
    Handle the OAuth 2.0 authorization callback.

    Validates the state parameter to prevent CSRF attacks,
    then exchanges the authorization code for tokens.
    """
    # Check for errors from the authorization server
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        logger.error(f"OAuth error: {error} - {error_description}")
        return jsonify({
            "error": error,
            "error_description": error_description,
        }), 400

    # Validate state parameter (CSRF protection)
    received_state = request.args.get("state")
    stored_state = session.pop("oauth_state", None)

    if not received_state or not stored_state:
        logger.error("SECURITY: Missing state parameter in OAuth callback")
        abort(400, description="Missing state parameter")

    if not secrets.compare_digest(received_state, stored_state):
        logger.error("SECURITY: State parameter mismatch - possible CSRF attack")
        abort(400, description="Invalid state parameter")

    # Retrieve stored session context
    tenant_id = session.pop("oauth_tenant_id", None)
    redirect_uri = session.pop("oauth_redirect_uri", None)

    if not tenant_id or not redirect_uri:
        logger.error("SECURITY: Missing session context in OAuth callback")
        abort(400, description="Invalid session state")

    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(400, description="Invalid tenant configuration")

    # Re-validate redirect_uri from session (defense in depth)
    if not validate_redirect_uri_secure(redirect_uri, tenant_config):
        logger.error("SECURITY: Stored redirect_uri no longer valid")
        abort(400, description="Invalid redirect URI")

    # Get the authorization code
    code = request.args.get("code")
    if not code:
        logger.error("Missing authorization code in callback")
        abort(400, description="Missing authorization code")

    # Exchange authorization code for tokens
    token_data = exchange_code_for_tokens(code, tenant_config, redirect_uri)
    if not token_data:
        return jsonify({"error": "Token exchange failed"}), 500

    # Store tokens securely in session
    session["oauth_tokens"] = {
        "access_token": token_data.get("access_token"),
        "token_type": token_data.get("token_type"),
        "expires_in": token_data.get("expires_in"),
        "refresh_token": token_data.get("refresh_token"),
        "scope": token_data.get("scope"),
    }
    session["authenticated_tenant"] = tenant_id

    logger.info(f"Successful OAuth flow completion for tenant '{tenant_id}'")

    return jsonify({
        "message": "Authentication successful",
        "tenant_id": tenant_id,
        "token_type": token_data.get("token_type"),
        "scope": token_data.get("scope"),
        "expires_in": token_data.get("expires_in"),
    })


def exchange_code_for_tokens(code, tenant_config, redirect_uri):
    """Exchange an authorization code for access/refresh tokens."""
    token_request_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": redirect_uri,
        "client_id": tenant_config["client_id"],
        "client_secret": tenant_config["client_secret"],
    }

    try:
        response = requests.post(
            tenant_config["token_endpoint"],
            data=token_request_data,
            headers={"Accept": "application/json"},
            timeout=10,
        )
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        logger.error(f"Token exchange failed: {e}")
        return None


@app.route("/userinfo")
def get_userinfo():
    """Fetch user information using the stored access token."""
    tokens = session.get("oauth_tokens")
    tenant_id = session.get("authenticated_tenant")

    if not tokens or not tenant_id:
        abort(401, description="Not authenticated")

    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(400, description="Invalid tenant")

    access_token = tokens.get("access_token")
    if not access_token:
        abort(401, description="No access token available")

    try:
        response = requests.get(
            tenant_config["userinfo_endpoint"],
            headers={
                "Authorization": f"Bearer {access_token}",
                "Accept": "application/json",
            },
            timeout=10,
        )
        response.raise_for_status()
        return jsonify(response.json())
    except requests.exceptions.RequestException as e:
        logger.error(f"Userinfo request failed: {e}")
        return jsonify({"error": "Failed to fetch user info"}), 500


