@app.route("/security/demo")
def security_demo():
    """
    Demonstrates why 'if domain in redirect_uri' is insecure.
    This endpoint is for educational purposes only.
    """
    domain = "example.com"

    malicious_uris = [
        "https://evil.com/example.com/callback",
        "https://example.com.evil.com/callback",
        "https://evilexample.com/callback",
        "https://evil.com?param=example.com",
        "https://evil.com#example.com",
        "https://example.com@evil.com/callback",
    ]

    results = []
    for uri in malicious_uris:
        # Show the insecure check result
        insecure_result = domain in uri  # THIS IS THE VULNERABLE CHECK

        # Show what proper validation looks like
        parsed = urlparse(uri)
        hostname = parsed.hostname or ""
        secure_result = (
            hostname == domain
            or hostname.endswith(f".{domain}")
        )

        results.append({
            "uri": uri,
            "insecure_substring_check_passes": insecure_result,
            "would_attacker_steal_tokens": insecure_result and not secure_result,
            "secure_allowlist_check_passes": False,  # None are in our allowlist
        })

    return jsonify({
        "warning": "This demonstrates why 'if domain in redirect_uri' is dangerous",
        "domain_being_checked": domain,
        "attack_scenarios": results,
        "recommendation": (
            "Always use exact-match allowlists for redirect URI validation. "
            "See RFC 6749 Section 3.1.2.2."
        ),
    })


